import './PaginationCell.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import { Button } from '../../Button';
import type { PaginationCellProps } from './PaginationCell.types';

export const PaginationCell: FC<PaginationCellProps> = ({
	variant = 'text',
	active = false,
	startIcon,
	className,
	children,
	...props
}) => (
	<>
		{variant === 'text' && (
			<Button
				data-testid="PaginationCell"
				{...props}
				className={classNames(
					'dsb_pagination-cell',
					'dsb_pagination-cell__text',
					active && 'dsb_pagination-cell__text-active',
					className,
					'dsb_button__outlined',
				)}
			>
				{children}
			</Button>
		)}
		{variant === 'icon' && (
			<Button
				data-testid="PaginationCell"
				{...props}
				className={classNames('dsb_pagination-cell', 'dsb_pagination-cell__icon', className)}
				startIcon={startIcon}
			/>
		)}
	</>
);
